{
  "integrative": {
    "title": "Integrative Close",
    "objective": "Synthesize the relationship between earthing system arrangements and the specific conductors used in the ADS path.",
    "retrievalTextLines": [
      "To achieve Automatic Disconnection of Supply (ADS), a fault current must follow a continuous path from the point of the fault back to the transformer.",
      "This path relies on the specific arrangement of the supply (TT, TN-S, or TN-C-S) and the correct installation of both circuit-level and main-level conductors."
    ],
    "questionText": "A property is supplied by a cable where the neutral and earth functions are combined in the street but separated into two distinct terminals at the consumer's intake. Describe the path a fault current takes from a metal appliance casing back to the supplier's earth terminal, specifically naming the earthing system type and the two different green-and-yellow conductors the current must pass through.",
    "answerGuidance": [
      "The system is a TN-C-S arrangement (or PME).",
      "The fault current first travels from the appliance to the consumer unit via the CPC (Circuit Protective Conductor).",
      "The current then travels from the Main Earthing Terminal (MET) to the supplier's earth terminal via the Earthing Conductor."
    ],
    "hint": "Think about the letter codes for 'Combined' then 'Separate', and remember the difference between the wire for a single circuit and the 'master' wire for the whole board."
  }
}

